/* 
   DP over (dish index, capacity‐decay index, skip‐streak).
   caps[k] = floor(m * (2/3)^k). 
   dp[i][c][s]: max calories after i dishes, 
     c = how many consecutive eats since last full reset (idx in caps[]), 
     s = number of consecutive skips (0,1,2=>=2).
*/
#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const ll NEG_INF = -(1LL<<60);

int main(){
    ios::sync_with_stdio(false);
    cin.tie(NULL);

    int n; 
    ll m;
    cin >> n >> m;
    vector<ll> a(n);
    for(int i = 0; i < n; i++) 
        cin >> a[i];

    // 1) Precompute capacities: caps[k] = floor(m * (2/3)^k)
    vector<ll> caps;
    {
        ll cur = m;
        while(cur > 0){
            caps.push_back(cur);
            cur = (cur * 2) / 3;
        }
    }
    int K = caps.size();  // ~<=25

    // 2) DP array: dp[i][capIdx][skipStreak]
    // skipStreak: 0=eat last,1=one skip,2=two-or-more skips
    static ll dp[105][30][3];
    for(int i = 0; i <= n; i++)
        for(int c = 0; c < K; c++)
            for(int s = 0; s < 3; s++)
                dp[i][c][s] = NEG_INF;

    // Initial: before any dish, we consider we've already skipped >=2 hours => full reset
    dp[0][0][2] = 0;

    for(int i = 0; i < n; i++){
        for(int c = 0; c < K; c++){
            for(int s = 0; s < 3; s++){
                ll val = dp[i][c][s];
                if(val < 0 && i>0) continue;  // unreachable

                // Option 1: Eat this dish
                {
                    // If we have skipped >=2, capacity resets => effective index = 0
                    int eff = (s==2 ? 0 : c);
                    ll canEat = min(caps[eff], a[i]);
                    int c2 = min(eff + 1, K - 1);
                    int s2 = 0;
                    dp[i+1][c2][s2] = max(dp[i+1][c2][s2], val + canEat);
                }

                // Option 2: Skip this dish
                {
                    int s2 = min(s + 1, 2);
                    int c2 = (s2 == 2 ? 0 : c); 
                    dp[i+1][c2][s2] = max(dp[i+1][c2][s2], val);
                }
            }
        }
    }

    // Answer = best over all end-states
    ll ans = 0;
    for(int c = 0; c < K; c++){
        for(int s = 0; s < 3; s++){
            ans = max(ans, dp[n][c][s]);
        }
    }

    cout << ans << "\n";
    return 0;
}

