/* 
  Solution to "LCM Partition" by grouped 0/1 knapsack over prime‐powers.
  We maximize sum of logs of chosen prime‐powers (equivalently maximizing LCM),
  then fill leftover with 1's for exact sum N, yielding lexicographically minimal.
*/
#include <bits/stdc++.h>
using namespace std;

static const double NEG_INF = -1e300;
static const double EPS = 1e-9;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    // 1) Sieve primes up to N
    vector<bool> is_composite(N+1, false);
    vector<int> primes;
    for(int i = 2; i <= N; i++){
        if(!is_composite[i]){
            primes.push_back(i);
            if((long long)i * i <= N)
                for(int j = i*i; j <= N; j += i)
                    is_composite[j] = true;
        }
    }
    int P = primes.size();

    // 2) For each prime, precompute its powers ≤ N and log-values.
    vector<vector<pair<int,double>>> options(P);
    for(int idx = 0; idx < P; idx++){
        int p = primes[idx];
        long long w = p;
        while(w <= N){
            options[idx].push_back({int(w), log((double)w)});
            w *= p;
        }
    }

    // 3) DP arrays: dpVal[c] = best sum of logs for cost c
    vector<double> dpVal(N+1, NEG_INF), ndpVal(N+1, NEG_INF);
    dpVal[0] = 0.0;

    // 4) Parent pointers for backtracking
    // preCost[idx][c]: 前驱花费； pickW[idx][c]: 当前质数组是否选了 w (0=未选)
    vector<vector<short>> preCost(P, vector<short>(N+1));
    vector<vector<short>> pickW(P,   vector<short>(N+1));

    // 5) Grouped knapsack over primes, 1D->1D each group
    for(int idx = 0; idx < P; idx++){
        // [FIX] 准备下一层 dp 数组并初始化为前一层
        for(int c = 0; c <= N; c++){
            ndpVal[c] = dpVal[c];
            preCost[idx][c] = c;      // 默认不选，前驱不变
            pickW[idx][c]   = 0;      // w=0 表示不选
        }
        // 转移：只针对严格更优的 dp 值做更新
        for(int c = 0; c <= N; c++){
            double curV = dpVal[c];
            if(curV <= NEG_INF/2) continue;
            for(auto &opt: options[idx]){
                int w = opt.first;
                double lg = opt.second;
                int nc = c + w;
                if(nc > N) break;
                double nv = curV + lg;
                if(nv > ndpVal[nc] + EPS){
                    ndpVal[nc] = nv;
                    preCost[idx][nc] = c;
                    pickW[idx][nc]   = w;
                }
                // 相等时不更新，保留更 lex 小的旧方案
            }
        }
        // 切换到下一层
        dpVal.swap(ndpVal);
    }

    // 6) 选出最佳 c：最大 dpVal, tie-break 花费最小 (c 小 => 剩余1 多)
    double bestVal = NEG_INF;
    int bestCost = 0;
    for(int c = 0; c <= N; c++){
        double v = dpVal[c];
        if(v <= NEG_INF/2) continue;
        if(v > bestVal + EPS || (fabs(v - bestVal) <= EPS && c < bestCost)){
            bestVal = v;
            bestCost = c;
        }
    }

    // 7) 回溯所有选中的质数幂
    vector<int> sel;
    int c = bestCost;
    for(int idx = P-1; idx >= 0; idx--){
        int w = pickW[idx][c];
        int pc = preCost[idx][c];
        if(w > 0) sel.push_back(w);
        c = pc;
    }
    reverse(sel.begin(), sel.end());
    // sel 中的 w 已按质数增序，天然有序

    // 8) 输出：先输出 (N - bestCost) 个 '1'，再输出 sel
    bool first = true;
    for(int i = 0; i < N - bestCost; i++){
        if(!first) cout << ' ';
        cout << 1;
        first = false;
    }
    for(int x: sel){
        if(!first) cout << ' ';
        cout << x;
        first = false;
    }
    if(first){ // N>=1 时不会发生
        cout << 1;
    }
    cout << "\n";
    return 0;
}

