/* 
  Solution to "LCM Partition" by grouped 0/1 knapsack over prime‐powers.
  We maximize sum of logs of chosen prime‐powers (equivalently maximizing LCM),
  then fill leftover with 1's for exact sum N, yielding lexicographically minimal.
*/
#include <bits/stdc++.h>
using namespace std;

static const double NEG_INF = -1e300;
static const double EPS = 1e-9;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    // 1) Sieve primes up to N
    vector<bool> is_composite(N+1, false);
    vector<int> primes;
    for(int i = 2; i <= N; i++){
        if(!is_composite[i]){
            primes.push_back(i);
            if((long long)i * i <= N)
                for(int j = i*i; j <= N; j += i)
                    is_composite[j] = true;
        }
    }
    int P = primes.size();

    // 2) For each prime, precompute its powers ≤ N and log-values.
    vector<vector<pair<int,double>>> options(P);
    for(int idx = 0; idx < P; idx++){
        int p = primes[idx];
        long long w = p;
        while(w <= N){
            options[idx].push_back({int(w), log((double)w)});
            w *= p;
        }
    }

    // 3) dpVal[c] = best sum of logs for cost c
    vector<double> dpVal(N+1, NEG_INF);
    dpVal[0] = 0.0;

    // 4) Parent pointers for backtracking
    vector<vector<short>> preCost(P, vector<short>(N+1, -1));
    vector<vector<short>> pickW(P,   vector<short>(N+1, 0));

    // 5) activeCurr: 当前组前已到达的 c 值
    vector<int> activeCurr;
    activeCurr.reserve(N+1);
    activeCurr.push_back(0);

    // 6) Grouped knapsack over primes with“可达列表”优化
    for(int idx = 0; idx < P; idx++){
        int sz = activeCurr.size();
        // 暂存本组开始前的旧 dpVal
        vector<double> oldVal(sz);
        for(int i = 0; i < sz; i++){
            int c = activeCurr[i];
            oldVal[i] = dpVal[c];
            // [FIX] 记录 carry 情况：不选当前质数组任何幂
            preCost[idx][c] = c;
            pickW[idx][c]  = 0;
        }
        // 准备下一组的可达列表
        vector<int> activeNext;
        activeNext.reserve(sz + options[idx].size()*2);
        vector<char> nextReachable(N+1, 0);

        // 先把 carry 的 c 直接传递过去
        for(int c: activeCurr){
            activeNext.push_back(c);
            nextReachable[c] = 1;
        }
        // 再做转移：仅针对 activeCurr 中的 c
        for(int i = 0; i < sz; i++){
            int c = activeCurr[i];
            double curV = oldVal[i];
            for(auto &opt: options[idx]){
                int w = opt.first;
                int nc = c + w;
                if(nc > N) break;
                double nv = curV + opt.second;
                if(nv > dpVal[nc] + EPS){
                    // [FIX] 直接更新 dpVal，无需额外 ndpVal 拷贝
                    dpVal[nc] = nv;
                    preCost[idx][nc] = c;
                    pickW[idx][nc] = w;
                    if(!nextReachable[nc]){
                        nextReachable[nc] = 1;
                        activeNext.push_back(nc);
                    }
                }
            }
        }
        // 切换 activeCurr
        activeCurr.swap(activeNext);
    }

    // 7) 在 activeCurr 范围内选最佳 c：最大 dpVal, tie-break c 小
    double bestVal = NEG_INF;
    int bestCost = 0;
    for(int c: activeCurr){
        double v = dpVal[c];
        if(v <= NEG_INF/2) continue;
        if(v > bestVal + EPS || (fabs(v - bestVal) <= EPS && c < bestCost)){
            bestVal = v;
            bestCost = c;
        }
    }

    // 8) 回溯所有选中的质数幂
    vector<int> sel;
    sel.reserve(P);
    int c = bestCost;
    for(int idx = P-1; idx >= 0; idx--){
        int w = pickW[idx][c];
        int pc = preCost[idx][c];
        if(w > 0) sel.push_back(w);
        c = pc;
    }
    reverse(sel.begin(), sel.end());

    // 9) 输出：先输出 (N - bestCost) 个 '1'，再输出 sel
    bool first = true;
    for(int i = 0; i < N - bestCost; i++){
        if(!first) cout << ' ';
        cout << 1;
        first = false;
    }
    for(int x: sel){
        if(!first) cout << ' ';
        cout << x;
        first = false;
    }
    if(first){ // 当 N>=1 时不走此分支
        cout << 1;
    }
    cout << "\n";
    return 0;
}
